  1	// TODO (@rexagod): https://github.com/openshift/console/pull/10470#discussion_r766453369
  2	import * as React from 'react';
  3	import { useGetInternalClusterDetails } from '@odf/core/redux/utils';
  4	import { GraphEmpty } from '@odf/shared/charts';
  5	import ConsumerPopover from '@odf/shared/dashboards/utilization-card/ConsumerPopover';
  6	import { PrometheusMultilineUtilizationItem } from '@odf/shared/dashboards/utilization-card/prometheus-multi-utilization-item';
  7	import { PrometheusUtilizationItem } from '@odf/shared/dashboards/utilization-card/prometheus-utilization-item';
  8	import { FieldLevelHelp } from '@odf/shared/generic/FieldLevelHelp';
  9	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
 10	import {
 11	  humanizeBinaryBytes,
 12	  humanizeDecimalBytesPerSec,
 13	} from '@odf/shared/utils';
 14	import { ByteDataTypes } from '@openshift-console/dynamic-plugin-sdk/lib/api/internal-types';
 15	import { UtilizationDurationDropdown } from '@openshift-console/dynamic-plugin-sdk-internal';
 16	import { Card, CardHeader, CardTitle, Grid } from '@patternfly/react-core';
 17	import { useStorageClassQueryFilter } from '../../../hooks';
 18	import {
 19	  StorageDashboardQuery,
 20	  utilizationPopoverQueryMap,
 21	  UTILIZATION_QUERY,
 22	} from '../../../queries';
 23	import { humanizeIOPS, humanizeLatency } from './utils';
 24	import '@odf/shared/dashboards/utilization-card/utilization-card.scss';
 25	
 26	export const UtilizationContent: React.FC = () => {
 27	  const { t } = useCustomTranslation();
 28	
 29	  // name of the created StorageClasses are prefix by StorageCluster name,
 30	  // it is also the value of the "managedBy" label in the metrics.
 31	  const { clusterNamespace: clusterNs, clusterName: ocsCluster } =
 32	    useGetInternalClusterDetails();
 33	
 34	  const [scQueryfilter, scQueryfilterLoaded, scQueryfilterError] =
 35	    useStorageClassQueryFilter(clusterNs);
 36	
 37	  const storagePopover = React.useCallback(
 38	    ({ current }) => (
 39	      <ConsumerPopover
 40	        title={t('Used Capacity')}
 41	        current={current}
 42	        consumers={utilizationPopoverQueryMap(scQueryfilter)}
 43	        humanize={humanizeBinaryBytes}
 44	      />
 45	    ),
 46	    [t, scQueryfilter]
 47	  );
 48	
 49	  return (
 50	    <Grid className="pf-v6-u-ml-sm pf-v6-u-mr-xs">
 51	      {scQueryfilterLoaded && !scQueryfilterError && (
 52	        <>
 53	          <PrometheusUtilizationItem
 54	            title={t('Used capacity')}
 55	            utilizationQuery={
 56	              UTILIZATION_QUERY(ocsCluster, scQueryfilter)[
 57	                StorageDashboardQuery.CEPH_CAPACITY_USED
 58	              ]
 59	            }
 60	            humanizeValue={humanizeBinaryBytes}
 61	            byteDataType={ByteDataTypes.BinaryBytes}
 62	            TopConsumerPopover={storagePopover}
 63	          />
 64	          <PrometheusMultilineUtilizationItem
 65	            title={t('IOPS')}
 66	            queries={[
 67	              UTILIZATION_QUERY(ocsCluster)[
 68	                StorageDashboardQuery.UTILIZATION_IOPS_READ_QUERY
 69	              ],
 70	              UTILIZATION_QUERY(ocsCluster)[
 71	                StorageDashboardQuery.UTILIZATION_IOPS_WRITE_QUERY
 72	              ],
 73	            ]}
 74	            humanizeValue={humanizeIOPS(t)}
 75	            chartType="stacked-area"
 76	          />
 77	          <PrometheusMultilineUtilizationItem
 78	            title={t('Throughput')}
 79	            queries={[
 80	              UTILIZATION_QUERY(ocsCluster)[
 81	                StorageDashboardQuery.UTILIZATION_THROUGHPUT_READ_QUERY
 82	              ],
 83	              UTILIZATION_QUERY(ocsCluster)[
 84	                StorageDashboardQuery.UTILIZATION_THROUGHPUT_WRITE_QUERY
 85	              ],
 86	            ]}
 87	            humanizeValue={humanizeDecimalBytesPerSec}
 88	            chartType="stacked-area"
 89	          />
 90	          <PrometheusMultilineUtilizationItem
 91	            title={t('Latency')}
 92	            queries={[
 93	              UTILIZATION_QUERY(ocsCluster)[
 94	                StorageDashboardQuery.UTILIZATION_LATENCY_READ_QUERY
 95	              ],
 96	              UTILIZATION_QUERY(ocsCluster)[
 97	                StorageDashboardQuery.UTILIZATION_LATENCY_WRITE_QUERY
 98	              ],
 99	            ]}
100	            humanizeValue={humanizeLatency}
101	            chartType="grouped-line"
102	          />
103	          <PrometheusUtilizationItem
104	            title={t('Recovery')}
105	            utilizationQuery={
106	              UTILIZATION_QUERY(ocsCluster)[
107	                StorageDashboardQuery.UTILIZATION_RECOVERY_RATE_QUERY
108	              ]
109	            }
110	            humanizeValue={humanizeDecimalBytesPerSec}
111	          />
112	        </>
113	      )}
114	      {!scQueryfilterLoaded && !scQueryfilterError && <GraphEmpty loading />}
115	      {!!scQueryfilterError && <GraphEmpty />}
116	    </Grid>
117	  );
118	};
119	
120	const UtilizationCard: React.FC = () => {
121	  const { t } = useCustomTranslation();
122	
123	  return (
124	    <Card>
125	      <CardHeader
126	        actions={{
127	          actions: <UtilizationDurationDropdown />,
128	          hasNoOffset: false,
129	          className: undefined,
130	        }}
131	      >
132	        <CardTitle>
133	          {t('Utilization')}
134	          <FieldLevelHelp>
135	            {t(
136	              'Performance metrics over time showing IOPS, Latency and more. Each metric is a link to a detailed view of this metric.'
137	            )}
138	          </FieldLevelHelp>
139	        </CardTitle>
140	      </CardHeader>
141	      <UtilizationContent />
142	    </Card>
143	  );
144	};
145	
146	export default UtilizationCard;

